import Link from "next/link";
import {
  getAllConcepts,
  getAllLogs,
  getAllRelations,
  getConceptBySlug
} from "../../lib/content";

export default function ConceptPage({
  concept,
  relatedRelations,
  relatedLogs
}) {
  const compareItems = Array.isArray(concept.compare) ? concept.compare : [];
  const coreMechanismItems = Array.isArray(concept.core_mechanism)
    ? concept.core_mechanism
    : [];
  const whenToUseItems = Array.isArray(concept.when_to_use)
    ? concept.when_to_use
    : [];

  return (
    <main style={styles.page}>
      <div style={styles.container}>
        <Link href="/" style={styles.backLink}>
          Back to home
        </Link>

        <h1 style={styles.title}>{concept.title || concept.slug || "Concept"}</h1>
        <p style={styles.summary}>
          {concept.summary || "No summary available."}
        </p>

        <section style={styles.section}>
          <h2 style={styles.heading}>Mental model</h2>
          <p style={styles.text}>
            {concept.mental_model || "No mental model available."}
          </p>
        </section>

        <section style={styles.section}>
          <h2 style={styles.heading}>Core mechanism</h2>
          {coreMechanismItems.length === 0 ? (
            <p style={styles.text}>No core mechanism details available.</p>
          ) : (
            <ul style={styles.list}>
              {coreMechanismItems.map((item, index) => (
                <li key={`${item}-${index}`} style={styles.listItem}>
                  {item}
                </li>
              ))}
            </ul>
          )}
        </section>

        <section style={styles.section}>
          <h2 style={styles.heading}>When to use</h2>
          {whenToUseItems.length === 0 ? (
            <p style={styles.text}>No usage notes available.</p>
          ) : (
            <ul style={styles.list}>
              {whenToUseItems.map((item, index) => (
                <li key={`${item}-${index}`} style={styles.listItem}>
                  {item}
                </li>
              ))}
            </ul>
          )}
        </section>

        <section style={styles.section}>
          <h2 style={styles.heading}>Compare</h2>
          {compareItems.length === 0 ? (
            <p style={styles.text}>No comparison notes available.</p>
          ) : (
            <ul style={styles.list}>
              {compareItems.map((item, index) => (
                <li
                  key={`${item.target || "compare"}-${index}`}
                  style={styles.compareItem}
                >
                  <strong>{item.target || "Unknown target"}</strong>
                  <p style={styles.compareText}>
                    {item.difference || "No difference provided."}
                  </p>
                </li>
              ))}
            </ul>
          )}
        </section>

        <section style={styles.section}>
          <h2 style={styles.heading}>Related concepts</h2>
          {relatedRelations.length === 0 ? (
            <p style={styles.text}>No related concepts found.</p>
          ) : (
            <ul style={styles.list}>
              {relatedRelations.map((relation, index) => (
                <li
                  key={`${relation.targetConcept || "related"}-${index}`}
                  style={styles.listItem}
                >
                  <span style={styles.relationType}>
                    {relation.relationType || "related-to"}:
                  </span>{" "}
                  {relation.targetConcept ? (
                    <Link
                      href={`/concept/${relation.targetConcept}`}
                      style={styles.inlineLink}
                    >
                      {relation.targetConcept}
                    </Link>
                  ) : (
                    <span>Unknown concept</span>
                  )}
                </li>
              ))}
            </ul>
          )}
        </section>

        <section style={styles.section}>
          <h2 style={styles.heading}>Learning logs</h2>
          {relatedLogs.length === 0 ? (
            <p>No learning logs found.</p>
          ) : (
            <ul>
              {relatedLogs.map((log, index) => (
                <li key={`${log.topic || "log"}-${index}`}>
                  <p>
                    <strong>{log.topic || "Untitled log"}</strong>
                  </p>
                  <p>{log.trigger || "No trigger provided."}</p>
                  <p>{log.updated_model || "No updated model provided."}</p>
                </li>
              ))}
            </ul>
          )}
        </section>
      </div>
    </main>
  );
}

export function getStaticPaths() {
  const concepts = getAllConcepts();

  return {
    paths: concepts.map((concept) => ({
      params: {
        slug: concept.slug
      }
    })),
    fallback: false
  };
}

export function getStaticProps({ params }) {
  const concept = getConceptBySlug(params.slug);
  const relatedRelations = getAllRelations()
    .filter(
      (relation) =>
        relation.from === params.slug || relation.to === params.slug
    )
    .map((relation) => ({
      relationType: relation.relation_type,
      targetConcept:
        relation.from === params.slug ? relation.to : relation.from
    }));
  const relatedLogs = getAllLogs().filter((log) => {
    if (!Array.isArray(log.related_concepts)) {
      return false;
    }

    return log.related_concepts.includes(params.slug);
  });

  if (!concept) {
    return {
      notFound: true
    };
  }

  return {
    props: {
      concept,
      relatedRelations,
      relatedLogs
    }
  };
}

